decimal sumRfLiveFemale = 0;
decimal sumFemaleFeed = 0;
decimal sumRfLiveMale = 0;
decimal sumMaleFeed = 0;
decimal sumFemaleMort = 0;
decimal sumCullsFemale = 0;
decimal sumMaleMort = 0;
decimal sumMaleCulls = 0;
// Helper method to safely get decimal parameter values
private decimal GetParameterDecimalValue(XtraReport report, string paramName)
{
    if (report == null || report.Parameters == null)
        return 0;

    DevExpress.XtraReports.Parameters.Parameter param = report.Parameters[paramName];
    if (param != null && param.Value != null && param.Value != DBNull.Value)
    {
        decimal.TryParse(param.Value.ToString(), out decimal value);
        return value;
    }
    return 0;
}
private void xrTableCell22_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

    // Get values from fields
    decimal rfLiveFemale = Convert.ToDecimal(GetCurrentColumnValue("rf_LiveFemale") ?? 0);
    decimal femaleFeed = Convert.ToDecimal(GetCurrentColumnValue("FemaleFeed") ?? 0);

    // Calculate: (FemaleFeed / 7 / rf_LiveFemale) * 1000
    if (rfLiveFemale > 0) {
        decimal result = (femaleFeed / 7 / rfLiveFemale) * 1000;
        cell.Text = result.ToString("N1") ; // 1 decimal place with unit
    } else {
        cell.Text = "0.0";
    }
}

