}

private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
decimal rfLiveFemale = Convert.ToDecimal(GetCurrentColumnValue("rf_LiveFemale") ?? 0);
    decimal femaleFeed = Convert.ToDecimal(GetCurrentColumnValue("FemaleFeed") ?? 0);

    sumRfLiveFemale += rfLiveFemale;
    sumFemaleFeed += femaleFeed;

     // Accumulate male sums from each detail row
    sumRfLiveMale += Convert.ToDecimal(GetCurrentColumnValue("rf_LiveMale") ?? 0);
    sumMaleFeed += Convert.ToDecimal(GetCurrentColumnValue("MaleFeed") ?? 0);

     // Accumulate FemaleMort from each row
    sumFemaleMort += Convert.ToDecimal(GetCurrentColumnValue("FemaleMort") ?? 0);

     // --- Accumulate CullsFemale ---
    object v = GetCurrentColumnValue("CullsFemale");
    if (v != null && v != DBNull.Value)
    {
        decimal.TryParse(v.ToString(), out decimal culls);
        sumCullsFemale += culls;
    }
    v = GetCurrentColumnValue("MaleMort");
    if (v != null && v != DBNull.Value)
    {
        decimal.TryParse(v.ToString(), out decimal mort);
        sumMaleMort += mort;
    }
    v = GetCurrentColumnValue("MaleCulls");
    if (v != null && v != DBNull.Value)
    {
        decimal.TryParse(v.ToString(), out decimal culls);
        sumMaleCulls += culls;
    }

    }

private void xrTableCell45_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

    decimal days = 7;

    if (sumRfLiveFemale > 0 && days > 0) {
        decimal result = (sumFemaleFeed / days / sumRfLiveFemale) * 1000;
        cell.Text = result.ToString("N1");
    } else {
        cell.Text = "0.0";
    }
}

private void xrTableCell46_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

    // Get days from parameter or default to 7
    decimal days = 7;

    // Apply equation to the ACCUMULATED SUMS: (TotalMaleFeed / days / TotalRfLiveMale) * 1000
    if (sumRfLiveMale > 0 && days > 0) {
        decimal result = (sumMaleFeed / days / sumRfLiveMale) * 1000;
        cell.Text = result.ToString("N1");
    } else {
        cell.Text = "0.0";
    }
}

private void xrTableCell51_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

       decimal femaleReceived = 0;
       decimal femaleDOA = 0;

    // --- FemaleReceived (parameter) ---
    if (this.Report.Parameters["FemaleReceived"] != null &&
        this.Report.Parameters["FemaleReceived"].Value != null)
    {
        decimal.TryParse(this.Report.Parameters["FemaleReceived"].Value.ToString(), out femaleReceived);
    }

    // --- FemaleDOA (parameter) ---
    if (Parameters["FemaleDOA"] != null &&
        Parameters["FemaleDOA"].Value != null)
    {
        decimal.TryParse(Parameters["FemaleDOA"].Value.ToString(), out femaleDOA);
    }
        // Calculate BirdsLeftFemale
    decimal birdsLeftFemale = femaleReceived - femaleDOA;

    // Calculate percentage using accumulated sum
    decimal denominator = birdsLeftFemale + femaleDOA;

    if (denominator > 0) {
        decimal result = (sumFemaleMort / denominator) * 100;
        cell.Text = result.ToString("N0") ;
    } else {
        cell.Text = "0";
    }
}

private void xrTableCell52_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    decimal femaleReceived = 0;
decimal femaleDOA = 0;
decimal birdsLeftFemale = 0;
decimal result = 0;

// --- FemaleReceived (parameter) ---
if (Parameters["FemaleReceived"] != null &&
    Parameters["FemaleReceived"].Value != null)
{
    decimal.TryParse(Parameters["FemaleReceived"].Value.ToString(), out femaleReceived);
}

// --- FemaleDOA (parameter) ---
if (Parameters["FemaleDOA"] != null &&
    Parameters["FemaleDOA"].Value != null)
{
    decimal.TryParse(Parameters["FemaleDOA"].Value.ToString(), out femaleDOA);
}

// --- BirdsLeftFemale ---
birdsLeftFemale = femaleReceived - femaleDOA;

// --- Equation ---
if (birdsLeftFemale > 0)
    result = (sumCullsFemale / (birdsLeftFemale + femaleDOA)) * 100m;

// --- Assign result ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("N0");

}

